  async function handleSendInvoice(inv) {
    setSendingInvoice(true);
    setSendInvoiceStatus("");
    setSendInvoiceError("");
    // On n'envoie JAMAIS de message vide : message perso si tapé, sinon le modèle poli.
    const messageFinal = sendInvoiceMessage.trim() || (invoiceIsOverdue(inv) ? messageRelanceFacture(inv, signatureEmetteur()) : messageParDefautFacture(inv.client_nom, inv.numero, signatureEmetteur()));
    try {
      const updated = await apiFetch(`/invoices/${inv.id}/send`, {
        method: "POST",
        body: JSON.stringify({
          emitter_nom: profilEntreprise || `${profilPrenom} ${profilNom}`.trim() || null,
          emitter_adresse: profilAdresse || null,
          emitter_siret: profilSiret || null,
          message: messageFinal,
        }),
      });
      setSendInvoiceStatus("sent");
      setViewingInvoice(updated);
      await loadInvoices();
    } catch (err) {
      setSendInvoiceStatus("error");
      setSendInvoiceError(err.message);
    } finally {
      setSendingInvoice(false);
    }
  }

